        },
        "text": "Data to be downloaded using SQL queries."
    },
    {
        "type": "ListItem",
        "element_id": "51d8e67259ab8a11d2fdfc5cb9bcf45e",
        "metadata": {
            "filename": "Bank Good Credit Loan.pptx",
            "file_directory": "tmpdocs",
